  activeId: string;
  onNavigate: (id: string) => void;
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ activeId, onNavigate, children }) => {
  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <aside className="w-full md:w-64 bg-slate-900 text-slate-300 flex-shrink-0 flex flex-col">
        <div className="p-6">
          <h1 className="text-xl font-bold text-white flex items-center gap-2">
            <span className="bg-blue-600 p-1 rounded text-sm">AT</span>
            ActivityTrack
          </h1>
          <p className="text-xs text-slate-500 mt-1">Architecture Blueprint</p>
        </div>

        <nav className="flex-1 overflow-y-auto px-4 pb-4 space-y-6">
          {[AppCategory.PUBLIC, AppCategory.AUTHENTICATED, AppCategory.FUTURE].map(category => (
            <div key={category}>
              <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2 px-2">
                {category}
