            <div className="text-xs">
              <p className="text-white font-medium">Lead Developer</p>
              <p className="text-slate-500">MVP Blueprint v1.0</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col bg-white">
        {/* Top Bar */}
        <header className="h-16 border-b flex items-center justify-between px-8 sticky top-0 bg-white z-10">
