import { PAGES } from './constants';
import { BlueprintView } from './components/BlueprintView';

const App: React.FC = () => {
  const [currentPageId, setCurrentPageId] = useState('landing');

  const currentPage = PAGES.find(p => p.id === currentPageId) || PAGES[0];

  return (
    <Layout activeId={currentPageId} onNavigate={setCurrentPageId}>
      {/* Overview Info Header for every page */}
      <div className="mb-10 text-center md:text-left">
        <h1 className="text-3xl font-extrabold text-slate-900 mb-2">
          {currentPage.title}
        </h1>
        <p className="text-slate-500 max-w-2xl">
          Blueprint specification for the {currentPage.title}. 
          Defines core functionality, structural components, and anticipated data relationships.
        </p>
      </div>

      <BlueprintView page={currentPage} />

      {/* Navigation Flow Section - Contextual for Authenticated pages */}
      {currentPage.id === 'dashboard' && (
        <div className="mt-16 p-8 bg-blue-50 rounded-2xl border border-blue-100 max-w-4xl mx-auto">
          <h3 className="text-xl font-bold text-blue-900 mb-6 flex items-center gap-2">
            🚀 Standard User Journey (UX Flow)
          </h3>
          <div className="flex flex-col md:flex-row items-center justify-between gap-4 text-sm font-medium">
            <div className="p-4 bg-white rounded-lg shadow-sm border border-blue-200 w-full text-center">Login / Auth</div>
            <div className="hidden md:block text-blue-300">➜</div>
            <div className="p-4 bg-blue-600 text-white rounded-lg shadow-sm w-full text-center font-bold">Dashboard Overview</div>
            <div className="hidden md:block text-blue-300">➜</div>
            <div className="p-4 bg-white rounded-lg shadow-sm border border-blue-200 w-full text-center">Log Activity</div>
            <div className="hidden md:block text-blue-300">➜</div>
            <div className="p-4 bg-white rounded-lg shadow-sm border border-blue-200 w-full text-center">Review Stats</div>
          </div>
          <p className="mt-6 text-xs text-blue-700 italic text-center">
            * Note: Users should be able to log activities from any authenticated screen via a floating persistent action button (PAB).
          </p>
        </div>
      )}
    </Layout>
  );
};

export default App;
